SELECT id, channelId, channelName, timestamp, user, content, contentMd5, createdAt, updatedAt
FROM DcChannelMessages
WHERE channelId = #{channelId}
AND timestamp >= #{beginTime}
AND timestamp <= #{endTime}
ORDER BY timestamp ASC

SELECT DISTINCT channelId
FROM DcChannelMessages
WHERE timestamp >= #{beginTime}
AND timestamp <= #{endTime}
ORDER BY channelId ASC
